// ─── Edit these to match your users' target roles ─────────────────
const ROLES = [
  'Software Engineer',
  'Backend Developer',
  'Frontend Developer',
  'Full Stack Developer',
  'DevOps Engineer',
  'Data Scientist',
];
const LOCATION = 'Israel';
// ──────────────────────────────────────────────────────────────────
return ROLES.map(role => ({ json: { role, location: LOCATION } }));

// Parse LinkedIn HTML job cards — outputs one item per job
const html = $input.first().json.data || '';
const jobs = [];
const blocks = html.split(/<li[^>]*>/).slice(1);

for (const block of blocks) {
  // Title
  const titleMatch = block.match(/class="base-search-card__title"[^>]*>([\s\S]*?)<\/h3>/i);
  if (!titleMatch) continue;
  const title = titleMatch[1].replace(/<[^>]+>/g, '').trim();
  if (!title || title.length < 2) continue;

  // Company — grab the full subtitle section then strip tags
  const compSection = block.match(/class="base-search-card__subtitle"[^>]*>([\s\S]*?)<\/h4>/i);
  const company = compSection
    ? compSection[1].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim()
    : '';

  // Location
  const locMatch = block.match(/class="job-search-card__location"[^>]*>([\s\S]*?)<\/span>/i);
  const location = locMatch
    ? locMatch[1].replace(/<[^>]+>/g, '').trim()
    : '';

  // URL — strip tracking params
  const urlMatch = block.match(/href="(https:\/\/[^"]*linkedin\.com\/jobs\/view\/[^"]+)"/i);
  let url = urlMatch ? urlMatch[1].replace(/&amp;/g, '&') : '';
  if (url.includes('?')) url = url.split('?')[0];

  // Job ID (for detail fetch)
  const jobIdMatch = url.match(/\/view\/(\d+)/);
  const jobId = jobIdMatch ? jobIdMatch[1] : '';

  if (!url && !title) continue;

  jobs.push({ title, company, location, url, jobId, source: 'linkedin' });
}

return jobs.map(job => ({ json: job }));

// Merge description from detail page with original job fields
const items = $input.all();
const parsed = $('Parse Job Cards').all();

return items.map((item, i) => {
  const html = item.json.data || '';
  const original = parsed[i] ? parsed[i].json : {};

  // Extract description — try multiple selectors LinkedIn uses
  let description = '';
  const descMatch =
    html.match(/class="show-more-less-html__markup[^"]*"[^>]*>([\s\S]*?)<\/div>/i) ||
    html.match(/class="description__text[^"]*"[^>]*>([\s\S]*?)<\/section>/i) ||
    html.match(/<section[^>]*class="[^"]*description[^"]*"[^>]*>([\s\S]*?)<\/section>/i);

  if (descMatch) {
    description = descMatch[1]
      .replace(/<[^>]+>/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .slice(0, 2000);
  }

  return {
    json: {
      ...original,
      description,
    }
  };
});

// Collect all jobs, deduplicate by URL
const jobs = $input.all().map(item => item.json);
const unique = [];
const seen = new Set();
for (const job of jobs) {
  const key = job.url || (job.title + '|' + job.company);
  if (key && !seen.has(key)) {
    seen.add(key);
    unique.push({
      title:       job.title       || '',
      company:     job.company     || '',
      location:    job.location    || '',
      url:         job.url         || '',
      description: job.description || '',
      skills:      [],
    });
  }
}
return [{ json: { source: 'linkedin', jobs: unique } }];
